import React, { useState } from 'react';
import { TAGS } from '../data';
import { Avatar, Stars } from './UI';

const ANTHROPIC_API = 'https://api.anthropic.com/v1/messages';

export default function BookingModal({ onClose, onSubmit, providers }) {
  const [step, setStep]     = useState(1);
  const [form, setForm]     = useState({ service: '', date: '', time: '', zip: '', notes: '' });
  const [suggested, setSuggested] = useState([]);
  const [loading, setLoading]     = useState(false);
  const [aiTip, setAiTip]         = useState('');

  const u = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const today = new Date().toISOString().split('T')[0];

  // Match providers to the typed service, fall back to any available
  const matchProviders = () => {
    const term = form.service.toLowerCase();
    const matched = providers.filter(p =>
      p.available && p.skills.some(s =>
        s.toLowerCase().includes(term.split(' ')[0]) ||
        term.includes(s.toLowerCase().split(' ')[0])
      )
    );
    return matched.length ? matched : providers.filter(p => p.available).slice(0, 3);
  };

  const findProviders = async () => {
    if (!form.date || !form.time) { alert('Please select a date and time.'); return; }
    setLoading(true);
    setSuggested(matchProviders());

    // Ask Claude for a quick tip
    try {
      const res = await fetch(ANTHROPIC_API, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model: 'claude-sonnet-4-20250514',
          max_tokens: 100,
          messages: [{
            role: 'user',
            content: `Give one short, practical tip (max 20 words) for hiring someone to help with: "${form.service}". Be specific and useful.`,
          }],
        }),
      });
      const data = await res.json();
      setAiTip(data.content?.[0]?.text || '');
    } catch (_) {}

    setLoading(false);
    setStep(3);
  };

  const book = (provider) => {
    onSubmit({
      ...form,
      providerId:   provider ? provider.id   : null,
      providerName: provider ? provider.name : null,
      price: Math.floor(50 + Math.random() * 60),
    });
    onClose();
  };

  return (
    <div className="modal-overlay" onClick={e => { if (e.target === e.currentTarget) onClose(); }}>
      <div className="modal">

        {/* Header */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
          <h2 style={{ fontSize: 20, color: 'var(--navy)' }}>Book a Service</h2>
          <button onClick={onClose} style={{ background: 'none', border: 'none', fontSize: 22, cursor: 'pointer', color: '#94a3b8' }}>✕</button>
        </div>

        {/* Step indicators */}
        <div style={{ display: 'flex', gap: 8, marginBottom: 28 }}>
          {['Details', 'Date & Time', 'Confirm'].map((label, i) => (
            <div key={i} style={{ flex: 1, textAlign: 'center' }}>
              <div style={{
                height: 4, borderRadius: 4, marginBottom: 6,
                background: step > i + 1 ? 'var(--green)' : step === i + 1 ? 'var(--navy)' : 'var(--gray-200)',
              }} />
              <span style={{ fontSize: 11, color: step === i + 1 ? 'var(--navy)' : 'var(--gray-400)', fontWeight: 500 }}>
                {label}
              </span>
            </div>
          ))}
        </div>

        {/* ---- STEP 1: What do you need ---- */}
        {step === 1 && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
            <div>
              <label>What do you need help with?</label>
              <input
                type="text"
                placeholder="e.g. Fix leaky faucet, dog walking, move furniture..."
                value={form.service}
                onChange={e => u('service', e.target.value)}
                autoFocus
              />
              <div className="tag-cloud" style={{ marginTop: 8 }}>
                {TAGS.slice(0, 12).map(t => (
                  <span key={t} className={`tag ${form.service === t ? 'active' : ''}`} onClick={() => u('service', t)}>
                    {t}
                  </span>
                ))}
              </div>
            </div>
            <div>
              <label>Your Zip Code</label>
              <input type="text" placeholder="Enter zip code" value={form.zip} onChange={e => u('zip', e.target.value)} maxLength={5} />
            </div>
            <div>
              <label>Additional Notes</label>
              <textarea
                rows={3} style={{ resize: 'none' }}
                placeholder="Any details that would help the provider..."
                value={form.notes}
                onChange={e => u('notes', e.target.value)}
              />
            </div>
            <button
              className="btn-primary"
              style={{ width: '100%', justifyContent: 'center' }}
              onClick={() => form.service && form.zip ? setStep(2) : alert('Please fill in service and zip code.')}
            >
              Continue →
            </button>
          </div>
        )}

        {/* ---- STEP 2: Date & Time ---- */}
        {step === 2 && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
            <div className="card" style={{ padding: 16, background: 'var(--gray-50)' }}>
              <div style={{ fontSize: 14, color: 'var(--gray-500)' }}>Service requested</div>
              <div style={{ fontWeight: 600, color: 'var(--navy)', marginTop: 2 }}>{form.service}</div>
              <div style={{ fontSize: 13, color: 'var(--gray-400)', marginTop: 2 }}>📍 {form.zip}</div>
            </div>
            <div>
              <label>Preferred Date</label>
              <input type="date" value={form.date} min={today} onChange={e => u('date', e.target.value)} />
            </div>
            <div>
              <label>Preferred Time</label>
              <input type="time" value={form.time} onChange={e => u('time', e.target.value)} />
            </div>
            <div style={{ display: 'flex', gap: 12 }}>
              <button className="btn-outline" onClick={() => setStep(1)} style={{ flex: 1 }}>← Back</button>
              <button
                className="btn-primary"
                style={{ flex: 2, justifyContent: 'center' }}
                onClick={findProviders}
                disabled={loading}
              >
                {loading ? 'Finding providers...' : 'Find Providers →'}
              </button>
            </div>
          </div>
        )}

        {/* ---- STEP 3: Confirm & Pick Provider ---- */}
        {step === 3 && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
            {aiTip && (
              <div style={{
                background: '#f0fdf4', border: '1px solid #bbf7d0',
                borderRadius: 10, padding: 14, fontSize: 13, color: '#166534',
              }}>
                💡 {aiTip}
              </div>
            )}

            <h3 style={{ fontSize: 15, color: 'var(--gray-600)' }}>
              Available Providers Near {form.zip}
            </h3>

            {suggested.map(p => (
              <div key={p.id} className="card" style={{ padding: 16, display: 'flex', gap: 12, alignItems: 'flex-start' }}>
                <Avatar name={p.name} idx={p.avatar} size={44} />
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 600, color: 'var(--navy)' }}>{p.name}</div>
                  <Stars rating={p.rating} />
                  <div style={{ fontSize: 12, color: 'var(--gray-500)', marginTop: 4 }}>
                    {p.skills.slice(0, 3).join(' · ')}
                  </div>
                </div>
                <button className="btn-primary btn-sm" onClick={() => book(p)}>Book</button>
              </div>
            ))}

            <button className="btn-outline" style={{ width: '100%' }} onClick={() => book(null)}>
              Post as Open Request (no provider yet)
            </button>
            <button
              style={{ background: 'none', border: 'none', color: 'var(--gray-500)', cursor: 'pointer', fontSize: 14 }}
              onClick={() => setStep(2)}
            >
              ← Back
            </button>
          </div>
        )}
      </div>
    </div>
  );
}
